import React, { useState, useEffect } from "react";
import Nav from "../Nav/Nav";
import "./CinemaManagement.css";

// Individual Slot Price Editor Component
function IndividualSlotPriceEditor({ slotNumber, slotType, currentPrice, cinemaId, onPriceUpdate }) {
  const [price, setPrice] = useState(currentPrice);
  const [isEditing, setIsEditing] = useState(false);
  const [isUpdating, setIsUpdating] = useState(false);

  const handleSave = async () => {
    if (price < 0) {
      alert("Price cannot be negative");
      return;
    }

    setIsUpdating(true);
    const success = await onPriceUpdate(cinemaId, slotNumber, price);
    setIsUpdating(false);

    if (success) {
      setIsEditing(false);
    }
  };

  const handleCancel = () => {
    setPrice(currentPrice);
    setIsEditing(false);
  };

  return (
    <div className="individual-slot-price-editor">
      <div className="slot-info">
        <span className="slot-name">Slot {slotNumber} ({slotType})</span>
        {isEditing ? (
          <div className="price-input-group">
            <input
              type="number"
              value={price}
              onChange={(e) => setPrice(parseInt(e.target.value) || 0)}
              min="0"
              className="price-input"
              disabled={isUpdating}
            />
            <button 
              className="save-btn"
              onClick={handleSave}
              disabled={isUpdating}
            >
              {isUpdating ? "Saving..." : "Save"}
            </button>
            <button 
              className="cancel-btn"
              onClick={handleCancel}
              disabled={isUpdating}
            >
              Cancel
            </button>
          </div>
        ) : (
          <div className="price-display">
            <span className="price">₹{currentPrice}</span>
            <button 
              className="edit-btn"
              onClick={() => setIsEditing(true)}
            >
              Edit
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

// Base Price Editor Component
function BasePriceEditor({ priceType, currentPrice, cinemaId, onBasePriceUpdate }) {
  const [price, setPrice] = useState(currentPrice);
  const [isEditing, setIsEditing] = useState(false);
  const [isUpdating, setIsUpdating] = useState(false);

  const handleSave = async () => {
    if (price < 0) {
      alert("Price cannot be negative");
      return;
    }

    setIsUpdating(true);
    const success = await onBasePriceUpdate(cinemaId, priceType, price);
    setIsUpdating(false);

    if (success) {
      setIsEditing(false);
    }
  };

  const handleCancel = () => {
    setPrice(currentPrice);
    setIsEditing(false);
  };

  return (
    <div className="base-price-editor">
      <div className="price-info">
        <span className="price-label">{priceType.charAt(0).toUpperCase() + priceType.slice(1).replace('_', ' ')} Price</span>
        {isEditing ? (
          <div className="price-input-group">
            <input
              type="number"
              value={price}
              onChange={(e) => setPrice(parseInt(e.target.value) || 0)}
              min="0"
              className="price-input"
              disabled={isUpdating}
            />
            <button 
              className="save-btn"
              onClick={handleSave}
              disabled={isUpdating}
            >
              {isUpdating ? "Saving..." : "Save"}
            </button>
            <button 
              className="cancel-btn"
              onClick={handleCancel}
              disabled={isUpdating}
            >
              Cancel
            </button>
          </div>
        ) : (
          <div className="price-display">
            <span className="price">₹{currentPrice}</span>
            <button 
              className="edit-btn"
              onClick={() => setIsEditing(true)}
            >
              Edit
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

