function CinemaManagement() {
  const [cinemas, setCinemas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingCinema, setEditingCinema] = useState(null);
  const [showPricingModal, setShowPricingModal] = useState(false);
  const [selectedCinemaForPricing, setSelectedCinemaForPricing] = useState(null);
  const [showIndividualPricingModal, setShowIndividualPricingModal] = useState(false);
  const [selectedCinemaForIndividualPricing, setSelectedCinemaForIndividualPricing] = useState(null);
  const [individualPricingData, setIndividualPricingData] = useState(null);
  const [formData, setFormData] = useState({
    cinema_name: "",
    cinema_location: "",
    google_maps_location: "",
    contact_info: {
      phone: "",
      email: ""
    },
    ongoing_movies: {
      movie_1: {
        name: "",
        start_date: "",
        end_date: "",
        trailer_link: ""
      },
      movie_2: {
        name: "",
        start_date: "",
        end_date: "",
        trailer_link: ""
      },
      movie_3: {
        name: "",
        start_date: "",
        end_date: "",
        trailer_link: ""
      },
      movie_4: {
        name: "",
        start_date: "",
        end_date: "",
        trailer_link: ""
      }
    },
    upcoming_movies: {
      movie_1: {
        name: "",
        trailer_link: ""
      },
      movie_2: {
        name: "",
        trailer_link: ""
      }
    },
    is_active: true
  });

  const [currentStep, setCurrentStep] = useState(1);
  const totalSteps = 7; // General details + 4 ongoing movies + 2 upcoming movies

  // API base URL
  const API_BASE_URL = "http://localhost:5000/api/cinemas";

  // Fetch cinemas from API
  const fetchCinemas = async () => {
    try {
      setLoading(true);
      const response = await fetch(API_BASE_URL);
      const data = await response.json();

      if (data.success) {
        setCinemas(data.data);
      } else {
        console.error("Error fetching cinemas:", data.message);
        alert("Error fetching cinemas: " + data.message);
      }
    } catch (error) {
      console.error("Error fetching cinemas:", error);
      alert("Error fetching cinemas. Please check if the backend server is running.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCinemas();
  }, []);

  const handleInputChange = (e) => {
    const { name, value } = e.target;

    if (name.includes(".")) {
      const [parent, child] = name.split(".");
      setFormData(prev => ({
        ...prev,
        [parent]: {
          ...prev[parent],
          [child]: value
        }
      }));
    } else {
      setFormData(prev => ({
        ...prev,
        [name]: value
      }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Client-side validation
    if (!formData.cinema_name || !formData.cinema_location) {
      alert("Please fill in all required fields (Cinema Name and Location)");
      return;
    }

    // Validate ongoing movies
    const ongoingMoviesValid = Object.values(formData.ongoing_movies).every(movie => 
      movie.name && movie.start_date && movie.end_date
    );

    if (!ongoingMoviesValid) {
      alert("Please fill in all required fields for ongoing movies (name, start date, and end date)");
      return;
    }

    // Validate upcoming movies
    const upcomingMoviesValid = Object.values(formData.upcoming_movies).every(movie => 
      movie.name
    );

    if (!upcomingMoviesValid) {
      alert("Please fill in all required fields for upcoming movies (name)");
      return;
    }

    try {
      const url = editingCinema ? `${API_BASE_URL}/${editingCinema._id}` : API_BASE_URL;
      const method = editingCinema ? 'PUT' : 'POST';

      console.log("📤 Sending cinema data:", JSON.stringify(formData, null, 2));

      const response = await fetch(url, {
        method: method,
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData)
      });

      const data = await response.json();
      console.log("📥 Response from server:", data);

      if (data.success) {
        alert(editingCinema ? "Cinema updated successfully!" : "Cinema added successfully!");
        setShowAddForm(false);
        setEditingCinema(null);
        resetForm();
        // Refresh the cinemas list
        fetchCinemas();
      } else {
        alert("Error: " + data.message);
        if (data.received) {
          console.log("Received fields:", data.received);
        }
      }
    } catch (error) {
      console.error("Error saving cinema:", error);
      alert("Error saving cinema. Please try again.");
    }
  };

  const resetForm = () => {
    setFormData({
      cinema_name: "",
      cinema_location: "",
      google_maps_location: "",
      contact_info: {
        phone: "",
        email: ""
      },
      ongoing_movies: {
        movie_1: {
          name: "",
          start_date: "",
          end_date: "",
          trailer_link: ""
        },
        movie_2: {
          name: "",
          start_date: "",
          end_date: "",
          trailer_link: ""
        },
        movie_3: {
          name: "",
          start_date: "",
          end_date: "",
          trailer_link: ""
        },
        movie_4: {
          name: "",
          start_date: "",
          end_date: "",
          trailer_link: ""
        }
      },
      upcoming_movies: {
        movie_1: {
          name: "",
          trailer_link: ""
        },
        movie_2: {
          name: "",
          trailer_link: ""
        }
      },
      is_active: true
    });
    setCurrentStep(1);
  };

  const handleNext = () => {
    if (currentStep < totalSteps) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handlePrev = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleEdit = (cinema) => {
    setFormData(cinema);
    setEditingCinema(cinema);
    setShowAddForm(true);
    setCurrentStep(1);
  };

  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this cinema?")) {
      try {
        const response = await fetch(`${API_BASE_URL}/${id}`, {
          method: 'DELETE'
        });

        const data = await response.json();

        if (data.success) {
          alert("Cinema deleted successfully!");
          // Refresh the cinemas list
          fetchCinemas();
        } else {
          alert("Error: " + data.message);
        }
      } catch (error) {
        console.error("Error deleting cinema:", error);
        alert("Error deleting cinema. Please try again.");
      }
    }
  };

  const toggleStatus = async (id) => {
    try {
      // First get the current cinema data
      const cinema = cinemas.find(c => c._id === id);
      if (!cinema) return;

      const response = await fetch(`${API_BASE_URL}/${id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ...cinema,
          is_active: !cinema.is_active
        })
      });

      const data = await response.json();

      if (data.success) {
        alert(`Cinema ${!cinema.is_active ? 'activated' : 'deactivated'} successfully!`);
        // Refresh the cinemas list
        fetchCinemas();
      } else {
        alert("Error: " + data.message);
      }
    } catch (error) {
      console.error("Error toggling cinema status:", error);
      alert("Error updating cinema status. Please try again.");
    }
  };

  const handlePricingClick = (cinema) => {
    setSelectedCinemaForPricing(cinema);
    setShowPricingModal(true);
  };

  const updateSlotPrice = async (cinemaId, slotType, slotNumber, newPrice) => {
    try {
      const response = await fetch(`${API_BASE_URL}/${cinemaId}/slot-prices`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          slotType,
          slotNumber,
          price: newPrice
        })
      });

      const data = await response.json();

      if (data.success) {
        // Refresh the cinemas list to show updated prices
        fetchCinemas();
        return true;
      } else {
        alert("Error updating price: " + data.message);
        return false;
      }
    } catch (error) {
      console.error("Error updating slot price:", error);
      alert("Error updating slot price. Please try again.");
      return false;
    }
  };

  const handleIndividualPricingClick = async (cinema) => {
    try {
      setSelectedCinemaForIndividualPricing(cinema);

      // Fetch individual pricing data
      const response = await fetch(`${API_BASE_URL}/${cinema._id}/individual-slot-prices`);
      const data = await response.json();

      if (data.success) {
        setIndividualPricingData(data.data);
        setShowIndividualPricingModal(true);
      } else {
        alert("Error fetching individual pricing data: " + data.message);
      }
    } catch (error) {
      console.error("Error fetching individual pricing data:", error);
      alert("Error fetching individual pricing data. Please try again.");
    }
  };

  const updateIndividualSlotPrice = async (cinemaId, slotNumber, newPrice) => {
    try {
      const response = await fetch(`${API_BASE_URL}/${cinemaId}/individual-slot-prices`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          slotNumber,
          price: newPrice
        })
      });

      const data = await response.json();

      if (data.success) {
        // Update local state
        setIndividualPricingData(data.data);
        // Refresh the cinemas list to show updated prices
        fetchCinemas();
        return true;
      } else {
        alert("Error updating individual slot price: " + data.message);
        return false;
      }
    } catch (error) {
      console.error("Error updating individual slot price:", error);
      alert("Error updating individual slot price. Please try again.");
      return false;
    }
  };

  const updateBasePrice = async (cinemaId, priceType, newPrice) => {
    try {
      const response = await fetch(`${API_BASE_URL}/${cinemaId}/individual-slot-prices`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          [priceType]: newPrice
        })
      });

      const data = await response.json();

      if (data.success) {
        // Update local state
        setIndividualPricingData(data.data);
        // Refresh the cinemas list to show updated prices
        fetchCinemas();
        return true;
      } else {
        alert("Error updating base price: " + data.message);
        return false;
      }
    } catch (error) {
      console.error("Error updating base price:", error);
      alert("Error updating base price. Please try again.");
      return false;
    }
  };

  return (
    <div>
      {/* Navbar */}
      <Nav />

      {/* Hero Section */}
      <section className="hero">
        <div className="hero-content">
          <h1>Cinema Management</h1>
          <p>Manage your cinema halls and movie listings</p>
          <button 
            className="cta-btn"
            onClick={() => setShowAddForm(true)}
          >
            Add New Cinema
          </button>
        </div>
      </section>

      {/* Add/Edit Form */}
      {showAddForm && (
        <section className="form-section">
          <div className="container">
            <div className="form-container">
              <div className="form-header">
                <h2>{editingCinema ? "Edit Cinema" : "Add New Cinema"}</h2>
                <button 
                  className="close-btn"
                  onClick={() => {
                    setShowAddForm(false);
                    setEditingCinema(null);
                    resetForm();
                  }}
                >
                  ×
                </button>
              </div>

              <div className="multi-step-form">
                <StepIndicator currentStep={currentStep} totalSteps={totalSteps} />

                <form onSubmit={handleSubmit} className="cinema-form">
                  {currentStep === 1 && (
                    <GeneralDetailsStep formData={formData} setFormData={setFormData} />
                  )}

                  {currentStep === 2 && (
                    <OngoingMovieStep 
                      movieKey="movie_1" 
                      movieData={formData.ongoing_movies.movie_1} 
                      setFormData={setFormData} 
                      stepNumber={1}
                    />
                  )}

                  {currentStep === 3 && (
                    <OngoingMovieStep 
                      movieKey="movie_2" 
                      movieData={formData.ongoing_movies.movie_2} 
                      setFormData={setFormData} 
                      stepNumber={2}
                    />
                  )}

                  {currentStep === 4 && (
                    <OngoingMovieStep 
                      movieKey="movie_3" 
                      movieData={formData.ongoing_movies.movie_3} 
                      setFormData={setFormData} 
                      stepNumber={3}
                    />
                  )}

                  {currentStep === 5 && (
                    <OngoingMovieStep 
                      movieKey="movie_4" 
                      movieData={formData.ongoing_movies.movie_4} 
                      setFormData={setFormData} 
                      stepNumber={4}
                    />
                  )}

                  {currentStep === 6 && (
                    <UpcomingMovieStep 
                      movieKey="movie_1" 
                      movieData={formData.upcoming_movies.movie_1} 
                      setFormData={setFormData} 
                      stepNumber={1}
                    />
                  )}

                  {currentStep === 7 && (
                    <UpcomingMovieStep 
                      movieKey="movie_2" 
                      movieData={formData.upcoming_movies.movie_2} 
                      setFormData={setFormData} 
                      stepNumber={2}
                    />
                  )}

                  <div className="form-actions">
                    <button 
                      type="button" 
                      onClick={() => {
                        setShowAddForm(false);
                        setEditingCinema(null);
                        resetForm();
                      }} 
                      className="btn-secondary"
                    >
                      Cancel
                    </button>

                    {currentStep > 1 && (
                      <button 
                        type="button" 
                        onClick={handlePrev} 
                        className="btn-secondary"
                      >
                        Previous
                      </button>
                    )}

                    {currentStep < totalSteps ? (
                      <button 
                        type="button" 
                        onClick={handleNext} 
                        className="btn-primary"
                      >
                        Next
                      </button>
                    ) : (
                      <button type="submit" className="btn-primary">
                        {editingCinema ? "Update Cinema" : "Add Cinema"}
                      </button>
                    )}
                  </div>
                </form>
              </div>
            </div>
          </div>
        </section>
      )}

      {/* Cinemas List */}
      <section className="cinemas-section">
        <div className="container">
          <h2>Your Cinemas</h2>

          {loading ? (
            <div className="loading">Loading cinemas...</div>
          ) : cinemas.length === 0 ? (
            <div className="no-cinemas">
              <h3>No cinemas found</h3>
              <p>Add your first cinema to get started.</p>
            </div>
          ) : (
            <div className="cinemas-grid">
              {cinemas.map((cinema) => (
                <div key={cinema._id} className="cinema-card">
                  <div className="cinema-header">
                    <h3>{cinema.cinema_name}</h3>
                    <span className={`status ${cinema.is_active ? "active" : "inactive"}`}>
                      {cinema.is_active ? "Active" : "Inactive"}
                    </span>
                  </div>

                  <div className="cinema-details">
                    <p className="location"> {cinema.cinema_location}</p>

                    <div className="movies-section">
                      <h4>Ongoing Movies:</h4>
                      <ul className="movies-list">
                        {cinema.ongoing_movies && Object.values(cinema.ongoing_movies).map((movie, index) => (
                          <li key={index}>
                            <strong>{movie.name}</strong>
                            <span className="movie-dates">
                              ({new Date(movie.start_date).toLocaleDateString()} - {new Date(movie.end_date).toLocaleDateString()})
                            </span>
                            {movie.trailer_link && (
                              <a href={movie.trailer_link} target="_blank" rel="noopener noreferrer" className="trailer-link">
                                Watch Trailer
                              </a>
                            )}
                          </li>
                        ))}
                      </ul>
                    </div>

                    <div className="upcoming-section">
                      <h4>Upcoming:</h4>
                      <div className="upcoming-movies">
                        {cinema.upcoming_movies && Object.values(cinema.upcoming_movies).map((movie, index) => (
                          <div key={index} className="upcoming-movie">
                            <p>{movie.name}</p>
                            {movie.trailer_link && (
                              <a href={movie.trailer_link} target="_blank" rel="noopener noreferrer" className="trailer-link">
                                Watch Trailer
                              </a>
                            )}
                          </div>
                        ))}
                      </div>
                    </div>

                    {cinema.google_maps_location && (
                      <div className="location-section">
                        <h4>Location:</h4>
                        <a href={cinema.google_maps_location} target="_blank" rel="noopener noreferrer" className="map-link">
                          View on Google Maps
                        </a>
                      </div>
                    )}

                    {cinema.advertisement_slots && (
                      <div className="advertisement-slots">
                        <h4>Advertisement Slots:</h4>
                        <div className="slots-summary">
                          <div className="slot-category">
                            <span className="slot-label">Start (5 slots):</span>
                            <span className="slot-price">₹{cinema.advertisement_slots.start_slots?.[0]?.price || 10000} each</span>
                          </div>
                          <div className="slot-category">
                            <span className="slot-label">Interval (5 slots):</span>
                            <span className="slot-price">₹{cinema.advertisement_slots.interval_slots?.[0]?.price || 10000} each</span>
                          </div>
                          <div className="slot-category">
                            <span className="slot-label">End (5 slots):</span>
                            <span className="slot-price">₹{cinema.advertisement_slots.end_slots?.[0]?.price || 10000} each</span>
                          </div>
                        </div>
                      </div>
                    )}

                    {cinema.contact_info.phone && (
                      <p className="contact"> {cinema.contact_info.phone}</p>
                    )}
                    {cinema.contact_info.email && (
                      <p className="contact"> {cinema.contact_info.email}</p>
                    )}
                  </div>

                  <div className="cinema-actions">
                    <button 
                      className="btn-edit"
                      onClick={() => handleEdit(cinema)}
                    >
                      Edit
                    </button>
                    <button 
                      className="btn-pricing"
                      onClick={() => handlePricingClick(cinema)}
                    >
                      Manage Pricing
                    </button>
                    <button 
                      className="btn-individual-pricing"
                      onClick={() => handleIndividualPricingClick(cinema)}
                    >
                      Individual Pricing
                    </button>
                    <button 
                      className="btn-toggle"
                      onClick={() => toggleStatus(cinema._id)}
                    >
                      {cinema.is_active ? "Deactivate" : "Activate"}
                    </button>
                    <button 
                      className="btn-delete"
                      onClick={() => handleDelete(cinema._id)}
                    >
                      Delete
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </section>

      {/* Pricing Management Modal */}
      {showPricingModal && selectedCinemaForPricing && (
        <div className="modal-overlay">
          <div className="pricing-modal">
            <div className="modal-header">
              <h2>Manage Advertisement Slot Pricing</h2>
              <h3>{selectedCinemaForPricing.cinema_name}</h3>
              <button 
                className="close-btn"
                onClick={() => {
                  setShowPricingModal(false);
                  setSelectedCinemaForPricing(null);
                }}
              >
                ×
              </button>
            </div>

            <div className="pricing-content">
              {selectedCinemaForPricing.advertisement_slots && (
                <>
                  {/* Start Slots Pricing */}
                  <div className="pricing-section">
                    <h4>Start Slots (Before Movie)</h4>
                    <div className="slots-pricing-grid">
                      {selectedCinemaForPricing.advertisement_slots.start_slots?.map((slot, index) => (
                        <SlotPriceEditor
                          key={`start_${slot.slot_number}`}
                          slotType="start_slots"
                          slotNumber={slot.slot_number}
                          currentPrice={slot.price}
                          cinemaId={selectedCinemaForPricing._id}
                          onPriceUpdate={updateSlotPrice}
                        />
                      ))}
                    </div>
                  </div>

                  {/* Interval Slots Pricing */}
                  <div className="pricing-section">
                    <h4>Interval Slots (During Movie)</h4>
                    <div className="slots-pricing-grid">
                      {selectedCinemaForPricing.advertisement_slots.interval_slots?.map((slot, index) => (
                        <SlotPriceEditor
                          key={`interval_${slot.slot_number}`}
                          slotType="interval_slots"
                          slotNumber={slot.slot_number}
                          currentPrice={slot.price}
                          cinemaId={selectedCinemaForPricing._id}
                          onPriceUpdate={updateSlotPrice}
                        />
                      ))}
                    </div>
                  </div>

                  {/* End Slots Pricing */}
                  <div className="pricing-section">
                    <h4>End Slots (After Movie)</h4>
                    <div className="slots-pricing-grid">
                      {selectedCinemaForPricing.advertisement_slots.end_slots?.map((slot, index) => (
                        <SlotPriceEditor
                          key={`end_${slot.slot_number}`}
                          slotType="end_slots"
                          slotNumber={slot.slot_number}
                          currentPrice={slot.price}
                          cinemaId={selectedCinemaForPricing._id}
                          onPriceUpdate={updateSlotPrice}
                        />
                      ))}
                    </div>
                  </div>
                </>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Individual Pricing Management Modal */}
      {showIndividualPricingModal && selectedCinemaForIndividualPricing && individualPricingData && (
        <div className="modal-overlay">
          <div className="individual-pricing-modal">
            <div className="modal-header">
              <h2>Individual Slot Pricing (15 Slots)</h2>
              <h3>{selectedCinemaForIndividualPricing.cinema_name}</h3>
              <button 
                className="close-btn"
                onClick={() => {
                  setShowIndividualPricingModal(false);
                  setSelectedCinemaForIndividualPricing(null);
                  setIndividualPricingData(null);
                }}
              >
                ×
              </button>
            </div>

            <div className="individual-pricing-content">
              {/* Base Prices Section */}
              <div className="base-prices-section">
                <h4>Base Prices (Apply to All Slots of Each Type)</h4>
                <div className="base-prices-grid">
                  <BasePriceEditor
                    priceType="starting_price"
                    currentPrice={individualPricingData.starting_price}
                    cinemaId={selectedCinemaForIndividualPricing._id}
                    onBasePriceUpdate={updateBasePrice}
                  />
                  <BasePriceEditor
                    priceType="interval_price"
                    currentPrice={individualPricingData.interval_price}
                    cinemaId={selectedCinemaForIndividualPricing._id}
                    onBasePriceUpdate={updateBasePrice}
                  />
                  <BasePriceEditor
                    priceType="ending_price"
                    currentPrice={individualPricingData.ending_price}
                    cinemaId={selectedCinemaForIndividualPricing._id}
                    onBasePriceUpdate={updateBasePrice}
                  />
                </div>
              </div>

              {/* Individual Slots Section */}
              <div className="individual-slots-section">
                <h4>Individual Slot Prices (Override Base Prices)</h4>
                <div className="individual-slots-grid">
                  {individualPricingData.slots?.map((slot, index) => (
                    <IndividualSlotPriceEditor
                      key={`individual_${slot.slot_number}`}
                      slotNumber={slot.slot_number}
                      slotType={slot.slot_type}
                      currentPrice={slot.price}
                      cinemaId={selectedCinemaForIndividualPricing._id}
                      onPriceUpdate={updateIndividualSlotPrice}
                    />
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Footer */}
      <footer className="footer">
        <div className="footer-content">
          <div className="footer-section">
            <h3>D&S Creations</h3>
            <p>Your premier destination for cinema advertising and entertainment.</p>
          </div>
          <div className="footer-section">
            <h4>Quick Links</h4>
            <ul>
              <li><a href="/mainhome">Home</a></li>
              <li><a href="/cinema-management">Cinema Management</a></li>
              <li><a href="/new-reservation">New Reservation</a></li>
              <li><a href="/my-reservations">My Reservations</a></li>
            </ul>
          </div>
          <div className="footer-section">
            <h4>Contact Info</h4>
            <p>Email: info@dscreations.com</p>
            <p>Phone: +1 (555) 123-4567</p>
          </div>
        </div>
        <div className="footer-bottom">
          <p>&copy; {new Date().getFullYear()} D&S Creations. All rights reserved.</p>
        </div>
      </footer>
    </div>
  );
}

export default CinemaManagement;
